const landingScreen = document.getElementById("landing-screen");
const freeQuizButton = document.getElementById("free-quiz-btn");
const startScreen = document.getElementById("start-screen");
const quizScreen = document.getElementById("quiz-screen");
const resultScreen = document.getElementById("result-screen");
const startButton = document.getElementById("start-btn");
const restartButton = document.getElementById("restart-btn");
const prevButton = document.getElementById("prev-btn");
const nextButton = document.getElementById("next-btn");
const questionText = document.getElementById("question-text");
const answersContainer = document.getElementById("answers-container");
const currentQuestionSpan = document.getElementById("current-question");
const totalQuestionsSpan = document.getElementById("total-questions");
const scoreSpan = document.getElementById("score");
const finalScoreSpan = document.getElementById("final-score");
const maxScoreSpan = document.getElementById("max-score");
const resultSummary = document.getElementById("result-summary");
const resultMessage = document.getElementById("result-message");
const progressBar = document.getElementById("progress");
const timerElement = document.getElementById("timer");
const timerCard = document.querySelector(".timer-card");
const resultPercent = document.getElementById("result-percent");
const scoreRing = document.querySelector(".score-ring");

const PROTECTION_KEY = "mardonbek-quiz-2026";
const QUIZ_PAYLOAD = "";
const quizQuestions = decodeQuizPayload(QUIZ_PAYLOAD, PROTECTION_KEY);

const QUESTION_TIME_SECONDS = 36;
const TOTAL_TIME_SECONDS = quizQuestions.length * QUESTION_TIME_SECONDS;
const RESULT_MESSAGES = [
  { min: 90, text: "A'lo natija! Siz mavzuni juda yaxshi egallagansiz." },
  { min: 75, text: "Zo'r! Bilimingiz mustahkam, faqat ayrim mavzularni takrorlang." },
  { min: 60, text: "Yaxshi natija. Xatolarni ko'rib chiqsangiz, ball yanada oshadi." },
  { min: 40, text: "O'rtacha natija. Grammatik va adabiyot bo'limlarini qayta ko'rib chiqing." },
  { min: 0, text: "Mashqni davom ettiring. Har bir urinish bilimni kuchaytiradi." },
];

let currentQuestionIndex = 0;
let score = 0;
let selectedAnswers = [];
let remainingSeconds = TOTAL_TIME_SECONDS;
let timerId = null;

totalQuestionsSpan.textContent = quizQuestions.length;
maxScoreSpan.textContent = quizQuestions.length;
document.getElementById("start-total").textContent = quizQuestions.length;
document.getElementById("start-time").textContent = formatTime(TOTAL_TIME_SECONDS);

freeQuizButton.addEventListener("click", showStartScreen);
startButton.addEventListener("click", startQuiz);
restartButton.addEventListener("click", restartQuiz);
prevButton.addEventListener("click", showPreviousQuestion);
nextButton.addEventListener("click", showNextQuestion);
initCopyProtection();

function decodeQuizPayload(payload, key) {
  const binary = atob(payload);
  const bytes = new Uint8Array(binary.length);

  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index) ^ key.charCodeAt(index % key.length);
  }

  return JSON.parse(new TextDecoder().decode(bytes));
}

function initCopyProtection() {
  const blockedEvents = ["copy", "cut", "contextmenu", "dragstart", "selectstart"];

  blockedEvents.forEach((eventName) => {
    document.addEventListener(eventName, blockDefaultAction, { capture: true });
  });

  document.addEventListener("keydown", (event) => {
    const key = event.key.toLowerCase();
    const blockedCombo =
      event.key === "F12" ||
      event.key === "PrintScreen" ||
      (event.ctrlKey && ["c", "u", "s", "p", "a"].includes(key)) ||
      (event.ctrlKey && event.shiftKey && ["i", "j", "c", "k"].includes(key));

    if (!blockedCombo) return;

    blockDefaultAction(event);

    if (event.key === "PrintScreen" && navigator.clipboard) {
      navigator.clipboard.writeText("").catch(() => {});
    }
  }, true);
}

function blockDefaultAction(event) {
  event.preventDefault();
  event.stopPropagation();
}
function showStartScreen() {
  switchScreen(landingScreen, startScreen);
}

function startQuiz() {
  currentQuestionIndex = 0;
  selectedAnswers = Array(quizQuestions.length).fill(null);
  remainingSeconds = TOTAL_TIME_SECONDS;

  updateScore();
  updateTimer();
  switchScreen(startScreen, quizScreen);
  showQuestion();
  startTimer();
}

function restartQuiz() {
  resultScreen.classList.remove("active");
  progressBar.style.width = "0%";
  scoreRing.style.setProperty("--score-angle", "0deg");
  startQuiz();
}

function showQuestion() {
  const currentQuestion = quizQuestions[currentQuestionIndex];
  const selectedAnswerIndex = selectedAnswers[currentQuestionIndex];

  currentQuestionSpan.textContent = currentQuestionIndex + 1;
  questionText.textContent = currentQuestion.question;
  progressBar.style.width = `${((currentQuestionIndex + 1) / quizQuestions.length) * 100}%`;

  answersContainer.innerHTML = "";
  answersContainer.classList.remove("question-enter");
  void answersContainer.offsetWidth;
  answersContainer.classList.add("question-enter");

  currentQuestion.answers.forEach((answer, answerIndex) => {
    const button = document.createElement("button");
    button.className = "answer-btn";
    button.type = "button";
    button.dataset.correct = String(answer.correct);
    button.dataset.answerIndex = String(answerIndex);
    button.innerHTML = `
      <span class="answer-label">${answer.label}</span>
      <span class="answer-text">${escapeHtml(answer.text)}</span>
    `;
    button.addEventListener("click", selectAnswer);
    answersContainer.appendChild(button);
  });

  if (selectedAnswerIndex !== null) {
    revealAnswers(answersContainer.children[selectedAnswerIndex]);
  }

  updateNavigation();
}

function selectAnswer(event) {
  const selectedButton = event.currentTarget;
  selectedAnswers[currentQuestionIndex] = Number(selectedButton.dataset.answerIndex);

  updateScore();
  revealAnswers(selectedButton);
}

function showPreviousQuestion() {
  if (currentQuestionIndex === 0) return;

  currentQuestionIndex -= 1;
  showQuestion();
}

function showNextQuestion() {
  if (currentQuestionIndex === quizQuestions.length - 1) {
    showResults();
    return;
  }

  currentQuestionIndex += 1;
  showQuestion();
}

function revealAnswers(selectedButton) {
  Array.from(answersContainer.children).forEach((button) => {
    button.classList.remove("correct", "incorrect", "selected");
    if (button.dataset.correct === "true") {
      button.classList.add("correct");
    } else if (button === selectedButton) {
      button.classList.add("incorrect");
    }
  });

  selectedButton.classList.add("selected");
}

function startTimer() {
  clearInterval(timerId);
  timerId = window.setInterval(() => {
    remainingSeconds -= 1;
    updateTimer();

    if (remainingSeconds <= 0) {
      showResults();
    }
  }, 1000);
}

function updateTimer() {
  timerElement.textContent = formatTime(Math.max(remainingSeconds, 0));
  timerCard.classList.toggle("warning", remainingSeconds <= 60);
}

function showResults() {
  clearInterval(timerId);
  progressBar.style.width = "100%";
  switchScreen(quizScreen, resultScreen);

  updateScore();
  const answeredCount = selectedAnswers.filter((answer) => answer !== null).length;
  const unansweredCount = quizQuestions.length - answeredCount;
  const percentage = Math.round((score / quizQuestions.length) * 100);
  const angle = (percentage / 100) * 360;

  finalScoreSpan.textContent = score;
  resultPercent.textContent = `${percentage}%`;
  scoreRing.style.setProperty("--score-angle", `${angle}deg`);
  resultSummary.textContent = `${answeredCount} ta savolga javob berdingiz, ${unansweredCount} ta savol javobsiz qoldi.`;
  resultMessage.textContent = RESULT_MESSAGES.find((message) => percentage >= message.min).text;
}

function updateScore() {
  score = selectedAnswers.reduce((total, answerIndex, questionIndex) => {
    if (answerIndex === null) return total;
    return quizQuestions[questionIndex].answers[answerIndex].correct ? total + 1 : total;
  }, 0);
  scoreSpan.textContent = score;
}

function updateNavigation() {
  prevButton.disabled = currentQuestionIndex === 0;
  nextButton.textContent = currentQuestionIndex === quizQuestions.length - 1 ? "Natijani ko'rish" : "Keyingi";
}

function switchScreen(currentScreen, nextScreen) {
  currentScreen.classList.remove("active");
  nextScreen.classList.add("active");
}

function formatTime(totalSeconds) {
  const minutes = Math.floor(totalSeconds / 60).toString().padStart(2, "0");
  const seconds = (totalSeconds % 60).toString().padStart(2, "0");
  return `${minutes}:${seconds}`;
}

function escapeHtml(value) {
  const div = document.createElement("div");
  div.textContent = value;
  return div.innerHTML;
}


